import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface Nutrition {
  calories: number;
  protein: string;
  carbs: string;
  fat: string;
}

interface RecipeData {
  recipe: {
    title: string;
    ingredientsCount: number;
    cookingTime: string;
    nutrition: Nutrition;
  };
}

export default function Widget() {
  const recipeData = response.data as RecipeData;
  const { title, ingredientsCount, cookingTime, nutrition } = recipeData.recipe;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 280, maxWidth: 380, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1 }}>
              {title}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              {ingredientsCount} Ingredients | {cookingTime}
            </Typography>
          </Box>

          <Stack direction="row" spacing={0.5}>
            <Chip label={`Calories: ${nutrition.calories}`} sx={{ fontSize: '11px', px: 1, py: 0.5 }} />
            <Chip label={`Protein: ${nutrition.protein}`} sx={{ fontSize: '11px', px: 1, py: 0.5 }} />
            <Chip label={`Carbs: ${nutrition.carbs}`} sx={{ fontSize: '11px', px: 1, py: 0.5 }} />
            <Chip label={`Fat: ${nutrition.fat}`} sx={{ fontSize: '11px', px: 1, py: 0.5 }} />
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
